const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { series_id } = msg.payload || {};
msg.url = series_id != null ? `${base}/api/v3/series/${series_id}` : `${base}/api/v3/series`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const arr = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
msg.payload = JSON.stringify(arr.map(s => ({
  id: s.id,
  title: s.title,
  year: s.year,
  status: s.status,
  monitored: s.monitored,
  network: s.network,
  seasonCount: s.seasons ? s.seasons.filter(x => x.seasonNumber > 0).length : null,
  episodeCount: s.episodeCount,
  episodeFileCount: s.episodeFileCount,
  tvdbId: s.tvdbId,
  path: s.path
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { series_id, season_number } = msg.payload || {};
const params = new URLSearchParams({ seriesId: String(series_id) });
if (season_number != null) params.set('seasonNumber', String(season_number));
msg.url = `${base}/api/v3/episode?${params}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const arr = Array.isArray(msg.payload) ? msg.payload : [];
msg.payload = JSON.stringify(arr.map(e => ({
  seasonNumber: e.seasonNumber,
  episodeNumber: e.episodeNumber,
  title: e.title,
  airDate: e.airDate || null,
  hasFile: e.hasFile,
  monitored: e.monitored
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const { start_date, end_date, unmonitored } = msg.payload || {};
const start = start_date || new Date().toISOString().split('T')[0];
const end = end_date || new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0];
const params = new URLSearchParams({ start, end, includeSeries: 'true', includeEpisodeFile: 'true' });
if (unmonitored) params.set('unmonitored', 'true');
msg.url = `${base}/api/v3/calendar?${params}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
msg.payload = JSON.stringify((Array.isArray(msg.payload) ? msg.payload : []).map(ep => ({
  seriesTitle: ep.series ? ep.series.title : null,
  episodeTitle: ep.title,
  seasonNumber: ep.seasonNumber,
  episodeNumber: ep.episodeNumber,
  airDateUtc: ep.airDateUtc,
  hasFile: ep.hasFile,
  monitored: ep.monitored
})));
return msg;

const base = env.get('SONARR_URL');
const key = env.get('SONARR_API_KEY');
if (!key) { node.error('SONARR_API_KEY not set'); return null; }
const params = new URLSearchParams({ pageSize: '50', includeSeries: 'true', includeEpisode: 'true' });
msg.url = `${base}/api/v3/queue?${params}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const records = msg.payload.records || [];
msg.payload = JSON.stringify(records.map(r => ({
  id: r.id,
  seriesTitle: r.series ? r.series.title : null,
  episodeTitle: r.episode ? r.episode.title : null,
  seasonNumber: r.episode ? r.episode.seasonNumber : null,
  episodeNumber: r.episode ? r.episode.episodeNumber : null,
  quality: r.quality ? r.quality.quality.name : null,
  status: r.status,
  trackedDownloadState: r.trackedDownloadState,
  timeleft: r.timeleft || null,
  size: r.size,
  sizeleft: r.sizeleft
})));
return msg;
